parameters.jsCode:
// 1. Get configuration, keywords, and search results
const config = $("Config").first().json;
const allKeywords = $("Data Sourcing").all();
const allSearchResults = $("Google Search").all();

// Use the limit from Config, or default to 5 if not found
const resultLimit = config.serp_results_amount || 10; 

let finalOutput = [];

// 2. Loop through every search result set
allSearchResults.forEach((searchResult, searchIndex) => {

  // Get the keyword from the matching index
  const keyword = allKeywords[searchIndex].json["Target Keyword"] || "Keyword Not Found";

  // Navigate the deep Decodo path
  let organicResults = searchResult.json.results[0].content.results.results.organic;

  // 3. LIMIT THE RESULTS HERE
  // slice(0, X) takes only the first X items from the array
  const limitedResults = organicResults.slice(0, resultLimit);

  // 4. Map each URL (up to the limit) to its own n8n item
  limitedResults.forEach(result => {
    finalOutput.push({
      json: {
        keyword: keyword,
        url: result.url,
        title: result.title,
        rank: result.pos
      },
      // Keeps the internal n8n breadcrumb trail alive
      pairedItem: {
        item: searchIndex
      }
    });
  });
});

return finalOutput;
